func fold(a []entry) []entry {
    seen := map[byte]entry{}
    for _, row := range a {
        key := row.Case[0]
        seen[key] = row
    }
    out := make([]entry, 0, len(seen))
    for _, row := range seen {
        out = append(out, row)
    }
    sort.Slice(out, func(i, j int) bool { return out[i].Case < out[j].Case })
    return out
}

func main() {
    if len(os.Args) != 3 {
        panic("usage: align raw final")
    }
    buf, err := os.ReadFile(os.Args[1])
